// 1. Get all the products we just fetched from Google Sheets
const products = $input.all().map(item => item.json);

// 2. Sort them based on our priority rules
const sortedProducts = products.sort((a, b) => {
  // Rule A: The product with the lowest "Times Posted" wins
  const countDiff = a["Times Posted"] - b["Times Posted"];
  if (countDiff !== 0) return countDiff; 

  // Rule B (Tie-Breaker): If they have the same post count (e.g., both are 0),
  // sort them alphabetically by Agent Name so it rotates cleanly
  return a["Agent Name"].localeCompare(b["Agent Name"]);
});

// 3. Select the absolute winner (the first one in our newly sorted list)
const selectedProduct = sortedProducts[0];

// 4. Output the winner and pass along the row number so we can update the sheet later
return {
  selectedProduct: selectedProduct,
  rowIndexToUpdate: selectedProduct.row_number,
  isPitch: false // We set this to false because this branch is strictly for products
};

const product = $json.selectedProduct;
let imageUrl = "";

if (product["Drive Image ID"] && product["Drive Image ID"] !== "") {
  // This uses the exact format from your screenshot!
  imageUrl = `https://lh3.googleusercontent.com/d/${product["Drive Image ID"]}`;
} else {
  const fallbackDriveId = "REPLACE_WITH_YOUR_PIXRIL_LOGO_DRIVE_ID";
  imageUrl = `https://lh3.googleusercontent.com/d/${fallbackDriveId}`;
}

return {
  ...$json,
  imageUrl: imageUrl
};

// 1. Grab the approved text and image from the form
const approvedCopy = $json["AI Generated Copy"];
let imageUrl = $json["Image URL"];

// 2. Reach back to the Image URL Converter (which safely runs on BOTH branches)
const rowIndex = $node["Image URL Converter"].json.rowIndexToUpdate;
const isPitch = $node["Image URL Converter"].json.isPitch;

// 3. If this is a pitch, we want absolutely no image attached
if (isPitch === true) {
  imageUrl = ""; 
}

// 4. Facebook Payload
const facebookPayload = {
  message: approvedCopy,
  url: imageUrl 
};

// 5. Threads Payload (preparing for tomorrow!)
const threadsPayload = {
  media_type: isPitch ? "TEXT" : "IMAGE",
  text: approvedCopy,
  image_url: imageUrl
};

return {
  facebook: facebookPayload,
  threads: threadsPayload,
  rowIndex: rowIndex,
  isPitch: isPitch
};

const userChoice = $json["Post Type"];

// We check what you selected in the dropdown
if (userChoice === "Custom Pitch") {
  return { isCustomPitchSlot: true };
} else {
  return { isCustomPitchSlot: false };
}
